<h1 class="h4 mb-3">Usuarios y permisos</h1>
<div class="card mb-3"><div class="card-header">Nuevo usuario de empresa</div><div class="card-body"><form method="POST" action="<?= e(url('/app/usuarios')) ?>" class="row g-2"><?= csrf_campo() ?><div class="col-md-3"><label class="form-label">Nombre</label><input name="nombre" class="form-control" required></div><div class="col-md-3"><label class="form-label">Correo</label><input name="correo" type="email" class="form-control" required></div><div class="col-md-2"><label class="form-label">Rol</label><select name="rol_id" class="form-select"><?php foreach($roles as $rol): ?><option value="<?= (int)$rol['id'] ?>"><?= e($rol['nombre']) ?></option><?php endforeach; ?></select></div><div class="col-md-2"><label class="form-label">Contraseña temporal</label><input name="password" class="form-control" value="123456"></div><div class="col-md-2"><label class="form-label">Estado</label><select name="estado" class="form-select"><option value="activo">Activo</option><option value="inactivo">Inactivo</option></select></div><div class="col-12"><button class="btn btn-primary btn-sm">Guardar usuario</button></div></form></div></div>
<div class="card"><div class="card-header">Listado de usuarios</div><div class="table-responsive"><table class="table table-sm table-hover mb-0 tabla-admin"><thead><tr><th>Nombre</th><th>Correo</th><th>Rol</th><th>Estado</th><th class="text-end">Acciones</th></tr></thead><tbody><?php foreach($usuarios as $u): ?><tr><td><?= e($u['nombre']) ?></td><td><?= e($u['correo']) ?></td><td><?= e($u['rol']) ?></td><td><span class="badge <?= $u['estado']==='activo' ? 'badge-estado-activo':'badge-estado-inactivo' ?>"><?= e($u['estado']) ?></span></td><td class="text-end"><div class="dropdown"><button class="btn btn-light btn-sm dropdown-toggle" data-bs-toggle="dropdown">Acciones</button><ul class="dropdown-menu dropdown-menu-end"><li><a class="dropdown-item" href="<?= e(url('/app/usuarios/ver/' . $u['id'])) ?>">Ver</a></li><li><a class="dropdown-item" href="<?= e(url('/app/usuarios/editar/' . $u['id'])) ?>">Editar</a></li><li><a class="dropdown-item" href="<?= e(url('/app/usuarios/editar/' . $u['id'])) ?>">Restablecer contraseña</a></li><li><a class="dropdown-item text-danger" href="<?= e(url('/app/usuarios/editar/' . $u['id'])) ?>">Desactivar</a></li></ul></div></td></tr><?php endforeach; ?></tbody></table></div></div>
